module top_module(input  i_Clk,      
   input  [3:0] i_Binary_Num, 
   output o_Segment_A,
   output o_Segment_B,
   output o_Segment_C,
   output o_Segment_D,
   output o_Segment_E,
   output o_Segment_F,
   output o_Segment_G
   );reg [6:0]	obf_r_Hex_Encoding = 7'h00;

	always @(posedge i_Clk)
	begin
		case (i_Binary_Num)
		4'b0000: obf_r_Hex_Encoding <= 7'h7E;
		4'b0001: obf_r_Hex_Encoding <= 7'h30;
		4'b0010: obf_r_Hex_Encoding <= 7'h6D;
		4'b0011: obf_r_Hex_Encoding <= 7'h79;
		4'b0100: obf_r_Hex_Encoding <= 7'h33;
		4'b0101: obf_r_Hex_Encoding <= 7'h5B;
		4'b0110: obf_r_Hex_Encoding <= 7'h5F;
		4'b0111: obf_r_Hex_Encoding <= 7'h70;
		4'b1000: obf_r_Hex_Encoding <= 7'h7F;
		4'b1001: obf_r_Hex_Encoding <= 7'h7B;
		4'b1010: obf_r_Hex_Encoding <= 7'h77;
		4'b1011: obf_r_Hex_Encoding <= 7'h1F;
		4'b1100: obf_r_Hex_Encoding <= 7'h4E;
		4'b1101: obf_r_Hex_Encoding <= 7'h3D;
		4'b1110: obf_r_Hex_Encoding <= 7'h4F;
		4'b1111: obf_r_Hex_Encoding <= 7'h47;
		endcase
	end   

  assign o_Segment_A = obf_r_Hex_Encoding[6];
  assign o_Segment_B = obf_r_Hex_Encoding[5];
  assign o_Segment_C = obf_r_Hex_Encoding[4];
  assign o_Segment_D = obf_r_Hex_Encoding[3];
  assign o_Segment_E = obf_r_Hex_Encoding[2];
  assign o_Segment_F = obf_r_Hex_Encoding[1];
  assign o_Segment_G = obf_r_Hex_Encoding[0];

endmodule
